SELECT competitor_name, email
FROM competitors
ORDER BY competitor_name ASC;

SELECT number_that_played
FROM event_entries
WHERE event_id = 1 AND entry_status = 'Confirmed';

SELECT COUNT(competitor_id) AS total_competitors
FROM event_entries
WHERE event_id = 1;

SELECT competitor_name, email
FROM competitors
WHERE competitor_id IN (1, 2, 3);

SELECT game_name 
FROM games 
WHERE game_date = '2023-10-01';

SELECT competitor_name 
FROM competitors 
ORDER BY competitor_name;

SELECT event_id, COUNT(*) AS total_entries
FROM event_entries
GROUP BY event_id;

SELECT DISTINCT c.competitor_name, c.email
FROM competitors c
JOIN event_entries e ON c.competitor_id = e.competitor_id;
